def find_zero(xs: list):
    left = -1.0
    right = 1.0
    while True:
        pl = poly(xs, left)
        pr = poly(xs, right)
        if pl * pr > 0:
            left *= 2
            right *= 2
        else:
            break
    while right - left > 1e-10:
        mid = (left + right) / 2
        pm = poly(xs, mid)
        if pm == 0:
            return mid
        if pl * pm < 0:
            right = mid
        else:
            left = mid
    return (left + right) / 2

