def encode(message):
    vowels = 'aeiou'
    result = ''
    for char in message:
        if char.isalpha():
            if char in vowels:
                new_char = chr(ord('a') + (ord(char) - ord('a') + 2) % 26)
                if char.isupper():
                    new_char = new_char.upper()
            else:
                new_char = char.swapcase()
            result += new_char
        else:
            result += char
    return result

