def minPath(grid, k):
    from heapq import heappush, heappop
    n = len(grid)
    directions = [(-1,0),(1,0),(0,-1),(0,1)]
    heap = []
    for i in range(n):
        for j in range(n):
            heappush(heap, (grid[i][j], i, j, [grid[i][j]]))
    while k > 1:
        val, x, y, path = heappop(heap)
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < n and 0 <= ny < n:
                new_val = grid[nx][ny]
                new_path = path + [new_val]
                heappush(heap, (new_val, nx, ny, new_path))
        k -= 1
    return heappop(heap)[3]

