def match_parens(lst):
    s1, s2 = lst
    combined = s1 + s2
    balance = 0
    for char in combined:
        if char == '(':
            balance += 1
        else:
            balance -= 1
        if balance < 0:
            return 'No'
    return 'Yes' if balance == 0 else 'No'

